return [
  {
    json: {
      item_id: '6d6e2f96ab2c4f86c6bfe17f0f3d5c21d7839ed4f3d8fbf35bc7f7f5ec34f7a1',
      source_type: 'rss',
      source_name: 'OpenAI YouTube',
      title: 'Example enriched item after LLM scoring',
      content_text: 'This example item already has structured scoring and matched-payload context, and now needs a deterministic action policy.',
      score: 0.82,
      score_scale: 100,
      category: 'AI Infra',
      tags: ['inbox', 'ai-information-processor'],
      dedupe_action: 'diff_push',
      matched_score: 0.89,
      ai_score: {
        keep_score: 82,
        notify_score: 64,
        reference_score: 88,
        action_score: 45,
        confidence: 0.76,
        decision_hint: 'keep_reference'
      },
      status: 'enriched'
    }
  }
];

const aiScore = $json.ai_score && typeof $json.ai_score === 'object' ? $json.ai_score : null;
if (!aiScore) {
  throw new Error('04a_action_policy requires ai_score from 02_enrich_with_llm');
}

const toNumber = (value, fallback = 0) => {
  const numericValue = Number(value);
  return Number.isFinite(numericValue) ? numericValue : fallback;
};

const keepScore = Math.round(toNumber(aiScore.keep_score, Math.round(toNumber($json.score, 0) * 100)));
const notifyScore = Math.round(toNumber(aiScore.notify_score, keepScore));
const referenceScore = Math.round(toNumber(aiScore.reference_score, keepScore));
const actionScore = Math.round(toNumber(aiScore.action_score, 0));
const confidence = toNumber(aiScore.confidence, 0);
const decisionHint = String(aiScore.decision_hint || 'review').trim() || 'review';
const dedupeAction = String($json.dedupe_action || 'full_push').trim() || 'full_push';

let shouldWriteToVault = false;
if (['keep_full', 'keep_reference', 'review'].includes(decisionHint)) {
  shouldWriteToVault = true;
}
if (decisionHint === 'skip') {
  shouldWriteToVault = false;
}
if (!shouldWriteToVault && (keepScore >= 60 || referenceScore >= 70 || actionScore >= 65)) {
  shouldWriteToVault = true;
}

const shouldNotify = shouldWriteToVault && notifyScore >= 75 && confidence >= 0.65;
const shouldUpsertQdrant = shouldWriteToVault;
const notificationMode = shouldNotify
  ? (dedupeAction === 'diff_push' ? 'incremental' : 'full')
  : 'silent';
const normalizedTags = Array.isArray($json.tags)
  ? $json.tags.map((tag) => String(tag).trim().toLowerCase()).filter(Boolean)
  : [];
if (decisionHint === 'review' || confidence < 0.5) {
  normalizedTags.push('needs-review');
}

return {
  json: {
    ...$json,
    tags: [...new Set(normalizedTags)],
    should_write_to_vault: shouldWriteToVault,
    should_notify: shouldNotify,
    should_upsert_qdrant: shouldUpsertQdrant,
    notification_mode: notificationMode,
    status: shouldWriteToVault ? 'enriched' : 'deduped',
    qdrant_operation: shouldUpsertQdrant ? 'pending' : 'skipped',
    qdrant_upsert_response: null
  }
};
